def compute_lps(pattern):
    m = len(pattern)
    lps = [0] * m
    length = 0   # length of previous longest prefix-suffix
    i = 1
    while i < m:
        if pattern[i] == pattern[length]:
            length += 1
            lps[i] = length
            i += 1
        else:
            if length != 0:
                # Don't increment i — try shorter prefix
                length = ___________
            else:
                lps[i] = 0
                i += 1
    return lps
